import { describe, it, expect } from "vitest";
import { advanceGenerations } from "./gameOfLife.js";

describe("Conway's Game of Life", () => {
  it("should return input unchanged when steps is 0", () => {
    const input = [[5, 5], [1, 2]];
    const result = advanceGenerations(input, 0);
    expect(result).toEqual(input);
  });
  it("should kill a single live cell (underpopulation)", () => {
    const input = [[0, 0]];
    const result = advanceGenerations(input, 1);
    expect(result).toEqual([]);
  });
  it("should keep a cell alive with exactly 2 neighbors", () => {
    // Three cells in a row: center cell (0, 0) has 2 neighbors
    const input = [[-1, 0], [0, 0], [1, 0]];
    const result = advanceGenerations(input, 1);
    // After 1 step, only center cell (0, 0) survives with 2 neighbors
    expect(result).toEqual([[0, 0]]);
  });
  it("should keep a cell alive with exactly 3 neighbors", () => {
    // Four-cell square (still life pattern called "block")
    const input = [[0, 0], [1, 0], [0, 1], [1, 1]];
    const result = advanceGenerations(input, 1);
    // All four cells have exactly 3 neighbors and survive
    // Output is lexicographically sorted: x ascending, then y ascending
    expect(result).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
  });
  it.todo("should kill a cell with more than 3 neighbors (overpopulation)");
  it.todo("should create a live cell from a dead cell with exactly 3 neighbors");
  it.todo("should maintain a tub still life after 1 generation");
  it.todo("should advance a blinker pattern correctly after 1 generation");
  it.todo("should advance multiple generations correctly");
  it.todo("should handle negative coordinates correctly");
  it.todo("should return sorted output (lexicographic order by x, then y)");
});

