// Game of Life rules constants
const SURVIVAL_NEIGHBORS = new Set([2, 3]);

const parseCell = (cellStr: string): [number, number] => {
  const [x, y] = cellStr.split(",").map(Number);
  return [x, y];
};

const cellToString = (x: number, y: number): string => {
  return `${x},${y}`;
};

const countNeighbors = (x: number, y: number, aliveSet: Set<string>): number => {
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      const neighborStr = `${x + dx},${y + dy}`;
      if (aliveSet.has(neighborStr)) {
        count++;
      }
    }
  }
  return count;
};

export const advanceGenerations = (
  aliveCells: [number, number][],
  steps: number
): [number, number][] => {
  if (steps === 0) {
    return aliveCells;
  }

  let alive = new Set(aliveCells.map(([x, y]) => cellToString(x, y)));

  for (let step = 0; step < steps; step++) {
    const nextAlive = new Set<string>();

    // Check all alive cells
    for (const cellStr of alive) {
      const [x, y] = parseCell(cellStr);
      const neighbors = countNeighbors(x, y, alive);

      // Survival: 2 or 3 neighbors
      if (SURVIVAL_NEIGHBORS.has(neighbors)) {
        nextAlive.add(cellStr);
      }
    }

    alive = nextAlive;
  }

  return Array.from(alive)
    .map(parseCell)
    .sort((a, b) => a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]);
};

